 * You can remove any number of elements (possibly zero) from nums.
 * Return the minimum number of removals required so that the XOR sum of the remaining elements equals target.
 * If it's impossible to reach target, return -1.
 * The XOR sum of an empty array is 0.
 */
fun solve(nums: Array<Long>, target: Long): Long {
