    // but a full subset enumeration (2^40) is too slow.
    // Since we are looking for a specific XOR sum, this problem is equivalent to finding a subset whose XOR sum is T,
    // and maximizing the size of this subset (which minimizes removals = N - max_subset_size).

    // We can use Meet-in-the-Middle (MITM) for N up to around 40.

    val mid = n / 2
    val firstHalf = nums.sliceArray(0 until mid)
    val secondHalf = nums.sliceArray(mid until n)

    // 1. Generate all possible XOR sums for the first half and store them with the count of elements used to achieve that sum.
    // map: XOR_sum -> list of subset sizes that achieve this sum
    val sums1 = mutableMapOf<Long, MutableList<Int>>()

    // Iterate through all 2^mid subsets of the first half
    for (i in 0 until (1 shl firstHalf.size)) {
        var currentXor = 0L
        var currentSize = 0
        for (j in 0 until firstHalf.size) {
            if ((i shr j) and 1 == 1) {
                currentXor = currentXor xor firstHalf[j]
                currentSize++
            }
        }
        sums1.getOrPut(currentXor) { mutableListOf() }.add(currentSize)
    }

    // 2. Generate all possible XOR sums for the second half and check against sums1.
    // We want (xor1 XOR xor2) = target, which means xor2 = target XOR xor1.

    var maxSubsetSize = -1 // Stores the maximum size of a subset found so far that XORs to target

    // Handle the case where the target is achieved using only the first half (xor2 = 0, size2 = 0)
    val targetXor = target
    if (sums1.containsKey(targetXor)) {
        sums1[targetXor]?.forEach { size1 ->
            maxSubsetSize = maxOf(maxSubsetSize, size1)
        }
    }

    // Iterate through all 2^(n-mid) subsets of the second half
    for (i in 0 until (1 shl secondHalf.size)) {
        var currentXor2 = 0L
        var currentSize2 = 0
        for (j in 0 until secondHalf.size) {
