                currentXor2 = currentXor2 xor secondHalf[j]
                currentSize2++
            }
        }

        // We need xor1 such that xor1 = target XOR xor2
        val requiredXor1 = targetXor xor currentXor2

        if (sums1.containsKey(requiredXor1)) {
            val sizes1 = sums1[requiredXor1]!!
            // For this pair (xor1, xor2), we want to maximize size1 + size2
            for (size1 in sizes1) {
                maxSubsetSize = maxOf(maxSubsetSize, size1 + currentSize2)
            }
        }
